import java.io.IOException;

public class CommandInjectionExample {
    public static void main(String[] args) {
        String userInput = "example.txt";

        // Vulnerable code: user input is directly used in a command without proper validation
        String command = "cat " + userInput;

        try {
            Process process = Runtime.getRuntime().exec(command);

            // Reading the output of the command
            java.util.Scanner scanner = new java.util.Scanner(process.getInputStream()).useDelimiter("\\A");
            String output = scanner.hasNext() ? scanner.next() : "";
            System.out.println("Output of the command: " + output);

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

